import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import ProtectedRoute from './components/ProtectedRoute';
import Login        from './pages/Login';
import Admin        from './pages/Admin';
import Doctor       from './pages/Doctor';
import Receptionist from './pages/Receptionist';
import Superadmin   from './pages/Superadmin';

function RootRedirect() {
  const { user } = useAuth();
  if (!user) return <Navigate to="/login" replace />;
  return <Navigate to={`/${user.role}`} replace />;
}

export default function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <Routes>
          <Route path="/"      element={<RootRedirect />} />
          <Route path="/login" element={<Login />} />
          <Route path="/admin" element={
            <ProtectedRoute role="admin"><Admin /></ProtectedRoute>
          } />
          <Route path="/doctor" element={
            <ProtectedRoute role="doctor"><Doctor /></ProtectedRoute>
          } />
          <Route path="/receptionist" element={
            <ProtectedRoute role="receptionist"><Receptionist /></ProtectedRoute>
          } />
          <Route path="/superadmin" element={
            <ProtectedRoute role="superadmin"><Superadmin /></ProtectedRoute>
          } />
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </BrowserRouter>
    </AuthProvider>
  );
}
